const today = new Date().toISOString().slice(0, 10);

return [
  {
    json: {
      category: 'world',
      categoryLabel: 'world',
      rssUrl: 'https://example.com/rss/world.xml',
      slugPrefix: `${today}-world-`,
      sourceHint: 'world feed placeholder'
    }
  },
  {
    json: {
      category: 'japan',
      categoryLabel: 'japan',
      rssUrl: 'https://example.com/rss/japan.xml',
      slugPrefix: `${today}-japan-`,
      sourceHint: 'japan feed placeholder'
    }
  },
  {
    json: {
      category: 'it-trend',
      categoryLabel: 'it-trend',
      rssUrl: 'https://example.com/rss/it-trend.xml',
      slugPrefix: `${today}-it-trend-`,
      sourceHint: 'it trend feed placeholder'
    }
  }
];

const rawFeed = typeof $json.body === 'string' ? $json.body : (typeof $json.data === 'string' ? $json.data : JSON.stringify($json));

const itemMatches = [...rawFeed.matchAll(/<item>[\s\S]*?<title>(.*?)<\/title>[\s\S]*?<link>(.*?)<\/link>[\s\S]*?<\/item>/gi)];
const parsedSources = itemMatches.slice(0, 3).map((match, index) => ({
  label: match[1].trim() || `${$json.categoryLabel} source ${index + 1}`,
  url: match[2].trim()
})).filter((source) => /^https?:\/\//i.test(source.url));

const titleMatches = [...rawFeed.matchAll(/<title>(.*?)<\/title>/gi)].map((match) => match[1].trim()).filter(Boolean);
const headlineHints = titleMatches.slice(1, 5);

return [
  {
    json: {
      ...$json,
      parsedSources: parsedSources.length > 0 ? parsedSources : [
        {
          label: `${$json.categoryLabel} RSS placeholder`,
          url: $json.rssUrl
        }
      ],
      headlineHints,
      feedExcerpt: rawFeed.slice(0, 4000)
    }
  }
];

let article;
try {
  const content = $json.choices?.[0]?.message?.content ?? '{}';
  article = JSON.parse(content);
} catch (error) {
  article = {
    slug: `${$json.slugPrefix}fallback-${Date.now()}`,
    title: `${$json.categoryLabel} update`,
    category: $json.category,
    publishedAt: $json.publishedAt,
    summaryLines: [
      `${$json.categoryLabel} autopost fallback article.`,
      'This example is for workflow testing.',
      'Replace the RSS feeds and prompt before production use.'
    ],
    bodyLines: [
      'OpenAI output was not readable as JSON, so a fallback article was created.',
      'Check the prompt and response shape before real use.'
    ],
    whyItMatters: 'This keeps the autopost pipeline testable.',
    tomoPoint: 'Start small, then refine the RSS and prompt.',
    thumbnailUrl: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=1200&q=80',
    tags: ['autopost', $json.category],
    sources: $json.parsedSources,
    initialEditorComment: {
      bodyLines: ['Autopost sample article. Please verify RSS and OpenAI connectivity.'],
      authorName: 'editor',
      shortId: 'editor'
    }
  };
}

const normalizedArticle = {
  ...article,
  category: article.category || $json.category,
  publishedAt: article.publishedAt || $json.publishedAt,
  sources: Array.isArray(article.sources) && article.sources.length > 0 ? article.sources : $json.parsedSources,
  initialEditorComment: article.initialEditorComment ?? {
    bodyLines: ['Autopost sample article.'],
    authorName: 'editor',
    shortId: 'editor'
  }
};

return [
  {
    json: {
      ...$json,
      articlePayload: normalizedArticle
    }
  }
];

const statusCode = $json.statusCode ?? 409;

return [
  {
    json: {
      statusCode,
      created: false,
      skipped: true,
      processed: false,
      createdCommentCount: null,
      aiReplySweeps: 0,
      note: 'duplicate-slug-skipped'
    }
  }
];

const createdCommentCount = typeof $json.createdCommentCount === 'number' ? $json.createdCommentCount : null;
const processed = $json.processed === true;

return [
  {
    json: {
      statusCode: $json.statusCode ?? 200,
      created: true,
      skipped: false,
      processed,
      createdCommentCount,
      aiReplySweeps: 3,
      note: processed ? 'created-and-swept' : 'created-no-queued-job'
    }
  }
];
